  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 9,
  "comparisons": [
    {
      "leftId": "dt_01_concept_06",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "Concept 07 bám sát yêu cầu về 'sản lượng bị đánh giá thấp' (con moi/ruốc) và quy trình chế biến (phơi sấy, phân loại) hơn Concept 06. Concept 06 tập trung vào cải tạo thuyền, dù hay nhưng thiên về kỹ thuật cơ khí hơn là chuỗi giá trị hải sản và thị trường hóa mà commission yêu cầu."
    },
    {
      "leftId": "dt_01_concept_06",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_06",
      "reason": "Concept 06 thể hiện agency của nhân vật qua tay nghề cải tạo công cụ lao động rõ rệt. Concept 08 vi phạm nhẹ ranh giới 'tọa độ chính xác' khi nhân vật biết rõ sò di chuyển đi đâu nhờ kiến thức tương lai, mang tính chất 'tìm kho báu' hơn là 'làm giàu bằng tay nghề'."
    },
    {
      "leftId": "dt_01_concept_06",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_09",
      "reason": "Concept 09 rất xuất sắc trong việc khai thác một mặt hàng đặc thù của huyện biển (muối) và cơ chế phân loại sản phẩm thủ công. Việc chia muối thành các loại cho mục đích khác nhau (ướp cá, làm mắm) khớp hoàn hảo với bối cảnh thị trường hóa ban đầu của thập niên 1980."
    },
    {
      "leftId": "dt_01_concept_06",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_06",
      "reason": "Concept 10 vi phạm nghiêm trọng bối cảnh lịch sử. Du lịch trải nghiệm và 'tour đi bộ' là khái niệm quá hiện đại, không khả thi trong bối cảnh kinh tế Việt Nam cuối thập niên 1980. Concept 06 thực tế và phù hợp với thể loại nam tần niên đại hơn."
    },
    {
      "leftId": "dt_01_concept_07",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_07",
      "reason": "Concept 07 tập trung vào việc nâng cấp giá trị một sản phẩm có sẵn nhưng bị coi rẻ, đúng tinh thần 'biến hiểu biết thành mẻ hàng'. Concept 08 dựa quá nhiều vào việc 'biết chỗ có hàng', dễ rơi vào lối mòn may mắn thay vì năng lực lao động."
    },
    {
      "leftId": "dt_01_concept_07",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_07",
      "reason": "Cả hai đều rất tốt, nhưng Concept 07 có nhịp độ và vòng thưởng (reward loop) rõ ràng hơn trong 3 chương đầu (mẻ ruốc sạch - quán phở - bữa cơm). Concept 09 về muối có phần chậm hơn và khó biến hóa đa dạng qua 30 chương bằng việc chế biến hải sản."
    },
    {
      "leftId": "dt_01_concept_07",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_07",
      "reason": "Concept 07 thắng tuyệt đối do Concept 10 không đáp ứng được yêu cầu về domain (đánh bắt, phân loại, muối, mắm) mà lại nhảy sang làm du lịch - một ngành chưa hình thành rõ nét ở nông thôn thời kỳ này."
    },
    {
      "leftId": "dt_01_concept_08",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_09",
      "reason": "Concept 09 tuân thủ tốt hơn các ranh giới về 'chi phí thật' và 'hao hụt thực tế'. Việc sàng lọc muối thủ công là một 'causal cost' rất thuyết phục. Concept 08 có phần dựa dẫm vào 'phép lạ' và sự mê tín của dân làng để che đậy kiến thức tương lai."
    },
    {
      "leftId": "dt_01_concept_08",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_08",
      "reason": "Dù Concept 08 hơi yếu về cơ chế tay nghề, nó vẫn giữ được chất 'biển' và 'niên đại'. Concept 10 hoàn toàn lạc lõng với yêu cầu về một câu chuyện làm giàu bằng nghề biển thực thụ."
    },
    {
      "leftId": "dt_01_concept_09",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_09",
      "reason": "Concept 09 thắng vì tính thực tế cao, ngôn ngữ và quan hệ làng xóm tự nhiên, đúng chất diêm dân Việt Nam. Concept 10 mang tư duy của một startup du lịch hiện đại áp đặt vào quá khứ."
    }
  ]
}
